import boto3
import re
from urllib.parse import urlparse
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def validate_endpoint_url(url):
    """Validate that the endpoint URL is HTTPS and has a valid domain"""
    try:
        parsed = urlparse(url)
        if parsed.scheme != 'https':
            return False
        if not parsed.netloc:
            return False
        # Basic domain validation
        domain_pattern = re.compile(
            r'^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$'
        )
        return bool(domain_pattern.match(parsed.netloc))
    except Exception:
        return False

def create_sns_subscription(topic_arn, endpoint_url):
    """Create SNS subscription with validation"""
    # Validate input
    if not validate_endpoint_url(endpoint_url):
        raise ValueError("Invalid endpoint URL")
    
    # Initialize SNS client
    sns_client = boto3.client('sns')
    
    try:
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint_url
        )
        logger.info(f"Subscription created successfully: {response['SubscriptionArn']}")
        return response
    except Exception as e:
        logger.error(f"Failed to create subscription: {str(e)}")
        raise

def main():
    # Get topic ARN from user
    topic_arn = input("Enter SNS Topic ARN: ").strip()
    
    # Get endpoint URL from user
    endpoint_url = input("Enter webhook endpoint URL: ").strip()
    
    try:
        create_sns_subscription(topic_arn, endpoint_url)
        print("Subscription created successfully")
    except Exception as e:
        print(f"Error: {str(e)}")

if __name__ == "__main__":
    main()